module RefModule (
    input wire clk,
    input wire rst,
    input wire en,
    output reg [15:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 16'b0000000000000000;
        end else if (en) begin
            count <= count + 1;
        end
    end

endmodule
